// And groups predicates with the AND operator between them.
func And(predicates ...predicate.InventoryLot) predicate.InventoryLot {
	return predicate.InventoryLot(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.InventoryLot) predicate.InventoryLot {
	return predicate.InventoryLot(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.InventoryLot) predicate.InventoryLot {
	return predicate.InventoryLot(sql.NotPredicates(p))
}
